protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable and
        // direct SQL queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
        // Preserve the old compound format so existing documents (e.g. "Product|123")
        // are still found by FindAsync / point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: HasIndex is no longer silently ignored — it now throws at startup.
    // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

